import{_ as e}from"./chunks/mario.B07hY3N3.js";import{c as r,Q as a,j as o,m as i}from"./chunks/framework.rlpw0eGz.js";const u=JSON.parse('{"title":"Mario AIO","description":"Інструкція з підключення, налаштування та оновлення модуля OpenIPC Mario AIO для FPV.","frontmatter":{"title":"Mario AIO","description":"Інструкція з підключення, налаштування та оновлення модуля OpenIPC Mario AIO для FPV.","head":[["link",{"rel":"canonical","href":"https://openfpv.com.ua/hardware/vtx/marioaio"}],["link",{"rel":"alternate","hreflang":"uk","href":"https://openfpv.com.ua/hardware/vtx/marioaio"}],["link",{"rel":"alternate","hreflang":"en","href":"https://openfpv.com.ua/en/hardware/vtx/marioaio"}],["link",{"rel":"alternate","hreflang":"x-default","href":"https://openfpv.com.ua/hardware/vtx/marioaio"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:url","content":"https://openfpv.com.ua/hardware/vtx/marioaio"}],["meta",{"property":"og:title","content":"Mario AIO"}],["meta",{"property":"og:description","content":"Інструкція з підключення, налаштування та оновлення модуля OpenIPC Mario AIO для FPV."}],["meta",{"property":"og:image","content":"https://openfpv.com.ua/og-hardware.png"}],["meta",{"property":"og:locale","content":"uk_UA"}],["meta",{"property":"og:locale:alternate","content":"en_US"}],["meta",{"name":"twitter:image","content":"https://openfpv.com.ua/og-hardware.png"}],["meta",{"name":"twitter:title","content":"Mario AIO"}],["meta",{"name":"twitter:description","content":"Інструкція з підключення, налаштування та оновлення модуля OpenIPC Mario AIO для FPV."}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@graph\\":[{\\"@type\\":\\"Organization\\",\\"@id\\":\\"https://openfpv.com.ua/#org\\",\\"name\\":\\"OpenFPV Ukraine\\",\\"url\\":\\"https://openfpv.com.ua\\",\\"logo\\":\\"https://openfpv.com.ua/logo-light.png\\",\\"sameAs\\":[\\"https://github.com/Maxwell456/openipc-docs-ukr\\"]},{\\"@type\\":\\"BreadcrumbList\\",\\"itemListElement\\":[{\\"@type\\":\\"ListItem\\",\\"position\\":1,\\"name\\":\\"Головна\\",\\"item\\":\\"https://openfpv.com.ua/\\"},{\\"@type\\":\\"ListItem\\",\\"position\\":2,\\"name\\":\\"Обладнання\\",\\"item\\":\\"https://openfpv.com.ua/hardware/vtx/\\"},{\\"@type\\":\\"ListItem\\",\\"position\\":3,\\"name\\":\\"Mario AIO\\"}]},{\\"@type\\":\\"TechArticle\\",\\"headline\\":\\"Mario AIO\\",\\"description\\":\\"Інструкція з підключення, налаштування та оновлення модуля OpenIPC Mario AIO для FPV.\\",\\"inLanguage\\":\\"uk-UA\\",\\"url\\":\\"https://openfpv.com.ua/hardware/vtx/marioaio\\",\\"image\\":\\"https://openfpv.com.ua/og-hardware.png\\",\\"dateModified\\":\\"2026-05-31T08:38:19.000Z\\",\\"author\\":{\\"@id\\":\\"https://openfpv.com.ua/#org\\"},\\"publisher\\":{\\"@id\\":\\"https://openfpv.com.ua/#org\\"}}]}"]]},"headers":[],"relativePath":"hardware/vtx/marioaio.md","filePath":"hardware/vtx/marioaio.md","lastUpdated":1780216699000}'),d={name:"hardware/vtx/marioaio.md"};function l(n,t,p,s,h,c){return a(),o("div",null,[...t[0]||(t[0]=[i('<h1 id="openipc-mario-aio" tabindex="-1">OpenIPC Mario AIO <a class="header-anchor" href="#openipc-mario-aio" aria-label="Permalink to &quot;OpenIPC Mario AIO&quot;">​</a></h1><p><img src="'+e+'" alt="" width="400px">&lt;</p><p><strong>OpenIPC Mario AIO</strong> — це компактний модуль для цифрової FPV-системи, який поєднує в собі камеру, передавач (VTX) та систему на чипі (SoC). Він розроблений для використання в дронах та інших FPV-проєктах, забезпечуючи високу якість зображення та низьку затримку передачі відео.</p><hr><h3 id="основні-характеристики" tabindex="-1">Основні характеристики <a class="header-anchor" href="#основні-характеристики" aria-label="Permalink to &quot;Основні характеристики&quot;">​</a></h3><table style="width:100%;border-collapse:collapse;margin:15px 0;"><thead><tr><th style="padding:10px;border:1px solid #ddd;text-align:left;">Характеристика</th><th style="padding:10px;border:1px solid #ddd;text-align:left;">Значення</th></tr></thead><tbody><tr><td style="padding:8px;border:1px solid #ddd;">Розмір плати</td><td style="padding:8px;border:1px solid #ddd;">30×32 мм</td></tr><tr><td style="padding:8px;border:1px solid #ddd;">Монтажні отвори</td><td style="padding:8px;border:1px solid #ddd;">4× M2</td></tr><tr><td style="padding:8px;border:1px solid #ddd;">Отвори радіатора</td><td style="padding:8px;border:1px solid #ddd;">20×20 мм</td></tr><tr><td style="padding:8px;border:1px solid #ddd;">Живлення</td><td style="padding:8px;border:1px solid #ddd;">2S–6S LiPo</td></tr><tr><td style="padding:8px;border:1px solid #ddd;">Вихідна потужність BEC (RF)</td><td style="padding:8px;border:1px solid #ddd;">5V до 3A</td></tr><tr><td style="padding:8px;border:1px solid #ddd;">Вихідна потужність BEC (MSIC)</td><td style="padding:8px;border:1px solid #ddd;">5V до 2A</td></tr><tr><td style="padding:8px;border:1px solid #ddd;">Інтерфейси</td><td style="padding:8px;border:1px solid #ddd;">UART, USB, Ethernet</td></tr><tr><td style="padding:8px;border:1px solid #ddd;">Підтримка SD-карти</td><td style="padding:8px;border:1px solid #ddd;">Так</td></tr><tr><td style="padding:8px;border:1px solid #ddd;">Охолодження</td><td style="padding:8px;border:1px solid #ddd;">Вбудований радіатор та вентилятор</td></tr></tbody></table><img src="https://github.com/user-attachments/assets/ad675599-61ce-4cec-a9bf-5933d907c53a" alt="" width="600px"><hr><h3 id="живлення-та-підключення" tabindex="-1">Живлення та підключення <a class="header-anchor" href="#живлення-та-підключення" aria-label="Permalink to &quot;Живлення та підключення&quot;">​</a></h3><ul><li>Живлення від акумулятора 2S–6S</li><li>Для низької напруги (2S–3S) рекомендується підключення <strong>4 дротів</strong> живлення через окремий конектор — потрібно більше струму.</li><li>Для напруги 4S і вище можна використовувати стандартне <strong>2-дротове</strong> підключення.</li><li>Для зниження мінімальної напруги живлення до ~5.4 В <strong>можна зняти два резистори</strong> на платі.</li></ul><hr><h3 id="виводи-uart-та-вхід-до-u-boot" tabindex="-1">Виводи UART та вхід до U-Boot <a class="header-anchor" href="#виводи-uart-та-вхід-до-u-boot" aria-label="Permalink to &quot;Виводи UART та вхід до U-Boot&quot;">​</a></h3><p>Для входу в режим завантаження U-Boot (debug mode) використовуйте UART:<br><strong>R0 / T0</strong> — контактні майданчики зверху на платі.</p><hr><h3 id="індикатори-led" tabindex="-1">Індикатори LED <a class="header-anchor" href="#індикатори-led" aria-label="Permalink to &quot;Індикатори LED&quot;">​</a></h3><ul><li><strong>Червоний мигає</strong> — живлення від батареї увімкнено</li><li><strong>Червоний постійно</strong> — Ethernet/USB з&#39;єднання</li><li><strong>Синій блимає</strong> — активний передавач RF</li><li><strong>Зелений</strong> — TBD (не реалізовано або змінюється)</li></ul><hr><img src="https://github.com/user-attachments/assets/e10e6671-553f-4840-aacd-16816be0813b" alt="" width="600px"><hr><h3 id="підключення-до-польотного-контролера" tabindex="-1">Підключення до польотного контролера <a class="header-anchor" href="#підключення-до-польотного-контролера" aria-label="Permalink to &quot;Підключення до польотного контролера&quot;">​</a></h3><p>Для підключення Mario AIO до польотного контролера (наприклад, SpeedyBee F405 WING) використовуйте наступні з&#39;єднання:</p><ul><li><strong>GND</strong> → GND на контролері</li><li><strong>VCC</strong> → VCC (перевірте відповідність напруги)</li><li><strong>RX</strong> → TX на контролері</li><li><strong>TX</strong> → RX на контролері</li></ul><blockquote><p>⚠️Перед увімкненням живлення переконайтесь у правильності всіх з&#39;єднань.</p></blockquote><hr><h3 id="налаштування-та-оновлення-прошивки" tabindex="-1">Налаштування та оновлення прошивки <a class="header-anchor" href="#налаштування-та-оновлення-прошивки" aria-label="Permalink to &quot;Налаштування та оновлення прошивки&quot;">​</a></h3><h3 id="підключення-через-usb" tabindex="-1">Підключення через USB <a class="header-anchor" href="#підключення-через-usb" aria-label="Permalink to &quot;Підключення через USB&quot;">​</a></h3><ol><li>Підключіть Mario AIO до комп&#39;ютера за допомогою USB-кабелю.</li><li>Якщо пристрій не розпізнається, встановіть драйвер <a href="https://github.com/user-attachments/files/16829005/corechip-sr9900-usb20-to-fast-ethernet-adapter-1750095.zip" target="_blank" rel="noreferrer"><strong>corechip-sr9900</strong></a>.</li><li>Налаштуйте мережевий адаптер USB: <ul><li>IP-адреса: <code>192.168.1.11</code></li><li>Маска підмережі: <code>255.255.255.0</code></li></ul></li><li>Підключіться до Mario AIO через SSH: <ul><li>IP-адреса: <code>192.168.1.10</code></li><li>Логін: <code>root</code></li><li>Пароль: <code>12345</code></li></ul></li></ol><h3 id="оновлення-прошивки" tabindex="-1">Оновлення прошивки <a class="header-anchor" href="#оновлення-прошивки" aria-label="Permalink to &quot;Оновлення прошивки&quot;">​</a></h3><ol><li>Завантажте <a href="https://github.com/OpenIPC/openipc-configurator/releases/" target="_blank" rel="noreferrer">Multiplatform Configurator</a>.</li><li>Firmware - OpenIPC - MarioAIO - натисніть Update.</li></ol><blockquote><p>⚠️Перед оновленням прошивки рекомендується зробити резервну копію налаштувань.</p></blockquote><hr><h3 id="налаштування-rf" tabindex="-1">Налаштування RF <a class="header-anchor" href="#налаштування-rf" aria-label="Permalink to &quot;Налаштування RF&quot;">​</a></h3><ul><li><strong>Максимальна потужність RF</strong>: 18 dBm</li><li><strong>Рекомендовані налаштування</strong>: <ul><li><code>stbc=1</code>, <code>ldpc=1</code></li><li><code>mcs</code> індекс: 1 або 3</li><li>Бітрейт відео: 4096 / 8192 / 12688</li></ul></li></ul><blockquote><p>⚠️Рекомендується обмежити потужність Txpower - 1 при живленні лише через USB.</p></blockquote><hr><h3 id="додаткові-ресурси" tabindex="-1">Додаткові ресурси <a class="header-anchor" href="#додаткові-ресурси" aria-label="Permalink to &quot;Додаткові ресурси&quot;">​</a></h3><ul><li><a href="https://github.com/OpenIPC/wiki" target="_blank" rel="noreferrer">OpenIPC Wiki</a></li><li><a href="https://github.com/OpenIPC/configurator" target="_blank" rel="noreferrer">OpenIPC Configurator</a></li><li><a href="https://www.youtube.com/watch?v=bgfCEThN3Kg" target="_blank" rel="noreferrer">Відеоогляд Mario AIO</a></li></ul>',37)])])}const b=r(d,[["render",l]]);export{u as __pageData,b as default};
